mapper.select:
select batch_code as batchCode, max(publish_type) as publishType, max(status) as status, max(remark) as remark, max(created_at) as createdAt, max(published_at) as publishedAt from t_r_publish_record where project_code = #{projectCode}
and status = #{status}
group by batch_code order by max(created_at) desc

select pr.batch_code as batchCode, wd.name as workflowName, pr.version_no as versionNo, pr.status from t_r_publish_record pr left join t_r_workflow_definition wd on wd.code = pr.workflow_definition_code where pr.batch_code in
#{code}
order by pr.id
